// Process Weather Data
const weather = $input.first().json;
const daily = weather.daily;
const parsedInfo = $('LLM Parse Request').first().json;
const targetDate = parsedInfo.date;

// WMO Weather Codes
const weatherCodes = {
  0: 'Trời quang đãng (Nắng)',
  1: 'Chủ yếu quang đãng', 2: 'Mây rải rác', 3: 'Nhiều mây',
  45: 'Sương mù', 48: 'Sương mù đóng băng',
  51: 'Mưa phùn nhẹ', 53: 'Mưa phùn vừa', 55: 'Mưa phùn dày',
  61: 'Mưa nhẹ', 63: 'Mưa vừa', 65: 'Mưa to',
  80: 'Mưa rào nhẹ', 81: 'Mưa rào vừa', 82: 'Mưa rào to',
  95: 'Giông bão', 96: 'Giông bão kèm mưa đá nhẹ', 99: 'Giông bão kèm mưa đá to'
};

// Tìm index ngày target
let targetIndex = daily.time.indexOf(targetDate);
if (targetIndex === -1) {
  // Fallback: dùng ngày gần nhất
  targetIndex = Math.min(6, daily.time.length - 1);
}

const code = daily.weather_code[targetIndex];
const maxTemp = daily.temperature_2m_max[targetIndex];
const minTemp = daily.temperature_2m_min[targetIndex];
const rainProb = daily.precipitation_probability_max[targetIndex];

// Nắng nếu weather code <= 3 VÀ xác suất mưa < 50%
const isSunny = code <= 3 && rainProb < 50;
const condition = isSunny ? 'sunny' : 'rainy';
const description = weatherCodes[code] || `Mã thời tiết ${code}`;

return [{
  json: {
    condition,
    isSunny,
    weatherCode: code,
    description,
    maxTemp,
    minTemp,
    rainProbability: rainProb,
    targetDate: daily.time[targetIndex],
    summary: `${description}, nhiệt độ ${minTemp}°C - ${maxTemp}°C, xác suất mưa: ${rainProb}%`,
    sessionId: parsedInfo.sessionId,
    city: parsedInfo.city,
    dateDescription: parsedInfo.dateDescription
  }
}];

