// Reasoning step - Decide what to search based on weather
const weather = $('Process Weather').first().json;
const parsedInfo = $('LLM Parse Request').first().json;

let reasoning, searchQuery, category;

if (weather.isSunny) {
  reasoning = `Thời tiết tại ${weather.city} vào ${weather.dateDescription}: ${weather.description}, nhiệt độ ${weather.maxTemp}°C. Xác suất mưa chỉ ${weather.rainProbability}% → Trời NẮNG ĐẸP. Theo yêu cầu, khi trời nắng sẽ tìm: ${parsedInfo.sunnyAction}`;
  searchQuery = `${parsedInfo.sunnyAction} ${weather.city} tốt nhất`;
  category = parsedInfo.sunnyAction;
} else {
  reasoning = `Thời tiết tại ${weather.city} vào ${weather.dateDescription}: ${weather.description}, xác suất mưa ${weather.rainProbability}% → Có khả năng MƯA. Theo yêu cầu, khi trời mưa sẽ tìm: ${parsedInfo.rainyAction}`;
  searchQuery = `${parsedInfo.rainyAction} ${weather.city} tốt nhất`;
  category = parsedInfo.rainyAction;
}

return [{
  json: {
    reasoning,
    searchQuery,
    category,
    sessionId: weather.sessionId,
    isSunny: weather.isSunny,
    weatherSummary: weather.summary,
    city: weather.city,
    dateDescription: weather.dateDescription
  }
}];

