// Process DuckDuckGo results
const ddg = $input.first().json;
const reasoningData = $('Reasoning Step').first().json;

let searchResults = '';

// Extract useful info from DuckDuckGo response
if (ddg.Abstract) {
  searchResults += `Tóm tắt: ${ddg.Abstract}\n\n`;
}

if (ddg.RelatedTopics && ddg.RelatedTopics.length > 0) {
  searchResults += 'Kết quả liên quan:\n';
  const topics = ddg.RelatedTopics.filter(t => t.Text).slice(0, 5);
  topics.forEach((topic, i) => {
    searchResults += `${i + 1}. ${topic.Text}\n`;
  });
}

if (!searchResults) {
  // Fallback: tạo context mặc định để LLM vẫn có thể trả lời
  searchResults = `Tìm kiếm "${reasoningData.searchQuery}" - API trả về kết quả hạn chế. LLM sẽ sử dụng kiến thức có sẵn để gợi ý.`;
}

return [{
  json: {
    searchResults,
    searchQuery: reasoningData.searchQuery,
    sessionId: reasoningData.sessionId,
    reasoning: reasoningData.reasoning,
    category: reasoningData.category,
    city: reasoningData.city,
    dateDescription: reasoningData.dateDescription,
    isSunny: reasoningData.isSunny,
    weatherSummary: reasoningData.weatherSummary
  }
}];

